from lxml import etree

def process_soap_request(xml_data):
    try:
        # Define the XML parser with DTD validation enabled
        parser = etree.XMLParser(dtd_validation=True)
        
        # Parse the SOAP request
        soap_envelope = etree.fromstring(xml_data, parser)
        
        # Find the body of the SOAP message
        body = soap_envelope.find('.//{http://schemas.xmlsoap.org/soap/envelope/}Body')
        
        if body is None:
            raise ValueError("SOAP Body not found in the request")
        
        # Extract and return the content of the Body
        return etree.tostring(body, pretty_print=True)
    
    except etree.XMLSyntaxError as e:
        print(f"XML Syntax Error: {e}")
    except Exception as e:
        print(f"An error occurred: {e}")

